<template>
  <div class="auth-page">
    <div class="auth-container">
      <!-- 左侧品牌区 -->
      <div class="auth-brand">
        <div class="auth-brand-content">
          <div class="auth-brand-logo">
            <span class="brand-bracket">&lt;</span>
            <span class="brand-slash">/</span>
            <span class="brand-bracket">&gt;</span>
          </div>
          <h2 class="auth-brand-title">AI-Code</h2>
          <p class="auth-brand-desc">智能编程学习平台</p>
          <div class="auth-brand-features">
            <div class="brand-feature">
              <i class="el-icon-success"></i>
              <span>AI 智能代码审查</span>
            </div>
            <div class="brand-feature">
              <i class="el-icon-success"></i>
              <span>实时编程问答</span>
            </div>
            <div class="brand-feature">
              <i class="el-icon-success"></i>
              <span>个性化学习路径</span>
            </div>
          </div>
        </div>
      </div>

      <!-- 右侧表单区 -->
      <div class="auth-form-wrap">
        <div class="auth-form-card">
          <div class="auth-form-header">
            <h2 class="auth-form-title">欢迎回来</h2>
            <p class="auth-form-desc">登录你的账号继续学习</p>
          </div>

          <el-form :model="form" :rules="rules" ref="formRef" label-width="0" size="large">
            <el-form-item prop="username">
              <el-input
                v-model="form.username"
                placeholder="用户名"
                prefix-icon="el-icon-user"
                class="auth-input"
              />
            </el-form-item>
            <el-form-item prop="password">
              <el-input
                v-model="form.password"
                type="password"
                placeholder="密码"
                prefix-icon="el-icon-lock"
                @keyup.enter="handleLogin"
                class="auth-input"
                show-password
              />
            </el-form-item>
            <el-form-item>
              <el-button type="primary" :loading="loading" class="auth-submit-btn" @click="handleLogin">
                {{ loading ? '登录中...' : '登录' }}
              </el-button>
            </el-form-item>
          </el-form>

          <div class="auth-form-footer">
            <span>还没有账号？</span>
            <router-link to="/register" class="auth-link">立即注册</router-link>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import { mapActions } from 'vuex';

export default {
  name: 'Login',
  data() {
    return {
      form: { username: '', password: '' },
      loading: false,
      rules: {
        username: [{ required: true, message: '请输入用户名', trigger: 'blur' }],
        password: [{ required: true, message: '请输入密码', trigger: 'blur' }]
      }
    };
  },
  methods: {
    ...mapActions(['login']),
    async handleLogin() {
      const valid = await this.$refs.formRef.validate().catch(() => false);
      if (!valid) return;

      this.loading = true;
      try {
        const res = await this.login(this.form);
        if (res.code === 200) {
          this.$message.success('登录成功！');
          const redirect = this.$route.query.redirect || '/';
          this.$router.push(redirect);
        }
      } finally {
        this.loading = false;
      }
    }
  }
};
</script>

